INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = '介護の日本語（N5レベル）' LIMIT 1), 1, 1, 'vocabulary', '{"intro": {"ja": "毎朝、患者さんに挨拶をする時に使う言葉を学びます。「おはようございます」「お目覚めですか」など、患者さんを尊重する丁寧な朝の声かけが重要です。", "vi": "Học những từ sử dụng khi chào hỏi bệnh nhân vào mỗi buổi sáng. \"おはようございます\" \"お目覚めですか\" v.v... Lời gọi hỏi buổi sáng lịch sự để tôn trọng bệnh nhân là quan trọng."}, "words": [{"word": "おはようございます", "reading": "おはようございます", "kanji": "お早うございます", "meaning": {"ja": "朝の敬語の挨拶", "vi": "Lời chào lịch sự buổi sáng"}, "examples": [{"ja": "おはようございます。お目覚めですか？", "vi": "Chào buổi sáng. Bạn đã thức dậy chưa?"},{"ja": "おはようございます。今日もいい天気ですね。", "vi": "Chào buổi sáng. Hôm nay trời đẹp lắm nhỉ."}], "care_example": "毎朝、患者さんに最初に挨拶する時に使う"}, {"word": "お目覚め", "reading": "おめざめ", "kanji": "お目覚め", "meaning": {"ja": "朝、目を覚ます敬語", "vi": "Từ lịch sự chỉ việc thức dậy buổi sáng"}, "examples": [{"ja": "お目覚めですか？", "vi": "Bạn đã thức dậy chưa?"},{"ja": "お目覚めいかがですか？", "vi": "Bạn thức dậy thế nào?"}], "care_example": "患者さんが起床したかどうかを確認する時"}, {"word": "いい天気ですね", "reading": "いいてんきですね", "kanji": "いい天気ですね", "meaning": {"ja": "天気が良いことを観察する", "vi": "Nhận xét thời tiết đẹp"}, "examples": [{"ja": "今日はいい天気ですね。散歩に行きましょう。", "vi": "Hôm nay trời đẹp. Chúng ta đi bộ nhé?"},{"ja": "いい天気で、気分もいいですね。", "vi": "Trời đẹp, tâm trạng cũng vui."}], "care_example": "患者さんとの会話を始めるための軽い話題"}, {"word": "どのように", "reading": "どのように", "kanji": "どのように", "meaning": {"ja": "状態や方法を聞く", "vi": "Hỏi về tình trạng hoặc cách thức"}, "examples": [{"ja": "昨晩、どのように寝ましたか？", "vi": "Tối qua bạn ngủ thế nào?"},{"ja": "今朝、どのようにお感じですか？", "vi": "Sáng nay bạn cảm thấy thế nào?"}], "care_example": "患者さんの夜間の睡眠や朝の状態を確認する"}, {"word": "お疲れ様です", "reading": "おつかれさまです", "kanji": "お疲れ様です", "meaning": {"ja": "努力や仕事をねぎらう敬語", "vi": "Từ lịch sự để cảm ơn nỗ lực hoặc công việc"}, "examples": [{"ja": "昨日は、お疲れ様でした。", "vi": "Hôm qua bạn mệt nhỏ."},{"ja": "毎日、お疲れ様です。", "vi": "Hàng ngày bạn đều mệt."}], "care_example": "患者さんが何かを頑張った時に労う"}, {"word": "調子", "reading": "ちょうし", "kanji": "調子", "meaning": {"ja": "状態、気分、調べ", "vi": "Tình trạng, tâm trạng, sức khỏe"}, "examples": [{"ja": "今日の調子はどうですか？", "vi": "Hôm nay bạn thế nào?"},{"ja": "いい調子ですね。", "vi": "Bạn khỏe khoắn."}], "care_example": "患者さんの体調や気分を聞く定番フレーズ"}, {"word": "気分", "reading": "きぶん", "kanji": "気分", "meaning": {"ja": "感情、気持ち、心の状態", "vi": "Cảm xúc, tâm trạng, trạng thái tinh thần"}, "examples": [{"ja": "気分がいいですか？", "vi": "Bạn cảm thấy tốt không?"},{"ja": "気分が悪いです。", "vi": "Tôi cảm thấy không tốt."}], "care_example": "患者さんの精神的な状態を確認する"}, {"word": "体調", "reading": "たいちょう", "kanji": "体調", "meaning": {"ja": "身体の状態、健康状態", "vi": "Tình trạng cơ thể, sức khỏe"}, "examples": [{"ja": "体調はいかがですか？", "vi": "Sức khỏe bạn thế nào?"},{"ja": "体調が悪い時は、寝てください。", "vi": "Khi sức khỏe không tốt, hãy nằm nghỉ."}], "care_example": "患者さんの身体の状態を正式に尋ねる"}], "dialogue": ["介護職: 「おはようございます。お目覚めですか？」", "患者さん: 「おはようございます。はい、目覚めました。」", "介護職: 「今日はいい天気ですね。昨晩、どのように寝ましたか？」", "患者さん: 「とてもいい調子です。よく寝ました。」", "介護職: 「そうですね。今朝の気分はいかがですか？」", "患者さん: 「気分がいいです。ありがとうございます。」", "介護職: 「体調もいいようですね。今日も頑張ります。」"], "key_phrases": [{"ja": "おはようございます", "vi": "Chào buổi sáng"},{"ja": "お目覚めですか", "vi": "Bạn đã thức dậy chưa"},{"ja": "今日の調子", "vi": "Tình trạng hôm nay"},{"ja": "気分がいい", "vi": "Cảm thấy tốt"}], "cultural_note": {"ja": "朝の挨拶は、患者さんとの一日の関係を始める重要な時間です。丁寧で温かい声かけは、患者さんに安心感を与え、良好なケア関係の基礎を作ります。", "vi": "Lời chào buổi sáng là thời gian quan trọng để bắt đầu mối quan hệ hàng ngày với bệnh nhân. Lời gọi hỏi lịch sự và ấm áp mang lại cảm giác an toàn cho bệnh nhân và tạo cơ sở cho mối quan hệ chăm sóc tốt."}, "quiz": [{"question": {"ja": "「おはようございます」はいつ使いますか？", "vi": "Khi nào sử dụng \"おはようございます\"?"}, "options": [{"ja": "夜間に患者さんに会った時", "vi": "Khi gặp bệnh nhân vào ban đêm"},{"ja": "朝、患者さんに挨拶する時", "vi": "Khi chào bệnh nhân vào buổi sáng"},{"ja": "昼食の時間に", "vi": "Lúc ăn trưa"},{"ja": "患者さんが寝ている時", "vi": "Khi bệnh nhân đang ngủ"}], "correct_answer": 1, "explanation": {"ja": "おはようございます は朝の敬語の挨拶です。毎朝、患者さんに最初に言う言葉です。", "vi": "おはようございます là lời chào lịch sự buổi sáng. Đó là từ đầu tiên nói với bệnh nhân mỗi buổi sáng."}, "difficulty": "easy"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = '介護の日本語（N5レベル）' LIMIT 1), 2, 1, 'vocabulary', '{"intro": {"ja": "食事の時に使う言葉を学びます。「お食事の時間です」「温かいですか」など、患者さんが安心して食事ができるような配慮の言葉が重要です。", "vi": "Học những từ sử dụng lúc ăn cơm. \"Đến giờ ăn cơm\" \"Nóng không?\" v.v... Những từ để chăm sóc để bệnh nhân có thể ăn một cách yên tâm là quan trọng."}, "words": [{"word": "お食事", "reading": "おしょくじ", "kanji": "お食事", "meaning": {"ja": "食事の敬語版", "vi": "Từ lịch sự để chỉ bữa ăn"}, "examples": [{"ja": "そろそろお食事の時間です。", "vi": "Sắp đến giờ ăn cơm."},{"ja": "お食事をお持ちしました。", "vi": "Tôi mang cơm đến rồi."}], "care_example": "患者さんに食事時間を知らせる時"}, {"word": "温かい", "reading": "あたたかい", "kanji": "温かい", "meaning": {"ja": "熱さのレベル、暖かい温度", "vi": "Độ nóng, nhiệt độ ấm"}, "examples": [{"ja": "お食事は温かいですか？", "vi": "Cơm nóng không?"},{"ja": "温かいお味噌汁をどうぞ。", "vi": "Vui lòng uống súp miso nóng."}], "care_example": "食事の温度が患者さんに合っているかを確認する"}, {"word": "冷たい", "reading": "つめたい", "kanji": "冷たい", "meaning": {"ja": "低い温度、涼しい", "vi": "Nhiệt độ thấp, lạnh"}, "examples": [{"ja": "冷たい水をください。", "vi": "Cho tôi nước lạnh."},{"ja": "冷たいデザートはいかがですか？", "vi": "Bạn có muốn tráng miệng lạnh không?"}], "care_example": "患者さんの好みに応じて飲み物の温度を確認する"}, {"word": "塩辛い", "reading": "しおからい", "kanji": "塩辛い", "meaning": {"ja": "塩の味が強い、しょっぱい", "vi": "Mặn, có vị mặn"}, "examples": [{"ja": "この料理は塩辛いですね。", "vi": "Món ăn này mặn nhỉ."},{"ja": "塩辛い物は避けてください。", "vi": "Hãy tránh những thứ mặn."}], "care_example": "患者さんの食事制限（高血圧など）を説明する時"}, {"word": "呑み込む", "reading": "のみこむ", "kanji": "呑み込む", "meaning": {"ja": "食べ物を飲む、嚥下する", "vi": "Nuốt, nuốt thức ăn"}, "examples": [{"ja": "よく呑み込んでください。", "vi": "Vui lòng nuốt chậm thôi."},{"ja": "呑み込みが悪いです。", "vi": "Khả năng nuốt của tôi kém."}], "care_example": "患者さんが食べ物を安全に呑み込むことを確認する"}, {"word": "一口", "reading": "ひとくち", "kanji": "一口", "meaning": {"ja": "口に入る一度の量、一回の食べ物", "vi": "Một miếng, một lần cắn"}, "examples": [{"ja": "一口、ゆっくり食べてください。", "vi": "Ăn một miếng, từ từ thôi."},{"ja": "一口、どうぞ。", "vi": "Mời bạn ăn một miếng."}], "care_example": "患者さんが一度に多く食べないよう指導する"}, {"word": "栄養", "reading": "えいよう", "kanji": "栄養", "meaning": {"ja": "食べ物に含まれる必要な成分", "vi": "Dưỡng chất có trong thực phẩm"}, "examples": [{"ja": "バランスのいい栄養が大事です。", "vi": "Cân bằng dinh dưỡng là quan trọng."},{"ja": "栄養が足りません。", "vi": "Thiếu dinh dưỡng."}], "care_example": "患者さんの食事の栄養バランスについて説明する"}, {"word": "食べやすい", "reading": "たべやすい", "kanji": "食べやすい", "meaning": {"ja": "食べるのが簡単である", "vi": "Dễ ăn"}, "examples": [{"ja": "柔らかい食べ物は食べやすいです。", "vi": "Đồ ăn mềm dễ ăn."},{"ja": "これは食べやすいですか？", "vi": "Cái này dễ ăn không?"}], "care_example": "患者さんの咀嚼や嚥下能力に合わせて食事を工夫する"}], "dialogue": ["介護職: 「お食事の時間です。温かいお食事をお持ちしました。」", "患者さん: 「ありがとうございます。温かいですね。」", "介護職: 「はい。今日のお食事は栄養がバランスよくできています。」", "患者さん: 「いい香りですね。」", "介護職: 「はい。一口、ゆっくり食べてください。呑み込みが大事です。」", "患者さん: 「わかりました。」", "介護職: 「食べやすいですか？何か必要ですか？」"], "key_phrases": [{"ja": "お食事の時間", "vi": "Giờ ăn cơm"},{"ja": "温かい/冷たい", "vi": "Nóng/Lạnh"},{"ja": "一口、ゆっくり", "vi": "Một miếng, từ từ"},{"ja": "呑み込む", "vi": "Nuốt"}], "cultural_note": {"ja": "食事介助は、単なる栄養摂取ではなく、患者さんの尊厳と安全を守るための重要なケアです。患者さんのペースを尊重し、食べやすい環境を整えることが、良好な食事時間を作ります。", "vi": "Hỗ trợ ăn cơm không chỉ là tiếp nhận dinh dưỡng mà là chăm sóc quan trọng để bảo vệ nhân phẩm và sự an toàn của bệnh nhân. Tôn trọng tốc độ của bệnh nhân và tạo môi trường dễ ăn tạo nên thời gian ăn cơm tốt."}, "quiz": [{"question": {"ja": "「温かいですか？」と聞く理由は？", "vi": "Tại sao hỏi \"温かいですか?\"?"}, "options": [{"ja": "患者さんの気分を聞く", "vi": "Hỏi tâm trạng của bệnh nhân"},{"ja": "食事の温度が患者さんに合っているか確認する", "vi": "Kiểm tra xem nhiệt độ thức ăn có phù hợp với bệnh nhân"},{"ja": "患者さんの好みを聞く", "vi": "Hỏi sở thích của bệnh nhân"},{"ja": "食事が安全かどうかを聞く", "vi": "Hỏi xem thức ăn có an toàn không"}], "correct_answer": 1, "explanation": {"ja": "食事の温度が患者さんの喜好や安全に関わるため、確認することが大切です。", "vi": "Nhiệt độ thức ăn liên quan đến sở thích và sự an toàn của bệnh nhân, nên cần xác nhận."}, "difficulty": "medium"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = '介護の日本語（N5レベル）' LIMIT 1), 3, 1, 'vocabulary', '{"intro": {"ja": "入浴の時に使う言葉を学びます。「お風呂の準備ができました」「温度はいかがですか」など、患者さんが快適で安全に入浴できるような配慮が重要です。", "vi": "Học những từ sử dụng lúc tắm. \"Bồn tắm đã sẵn sàng\" \"Nhiệt độ thế nào?\" v.v... Chăm sóc để bệnh nhân có thể tắm một cách thoải mái và an toàn là quan trọng."}, "words": [{"word": "お風呂", "reading": "おふろ", "kanji": "お風呂", "meaning": {"ja": "入浴するための水、浴室", "vi": "Nước tắm, phòng tắm"}, "examples": [{"ja": "お風呂の準備ができました。", "vi": "Bồn tắm đã sẵn sàng."},{"ja": "お風呂に入りましょう。", "vi": "Chúng ta đi tắm nhé."}], "care_example": "患者さんに入浴の準備ができたことを知らせる"}, {"word": "温度", "reading": "おんど", "kanji": "温度", "meaning": {"ja": "熱さの度合い", "vi": "Độ nóng"}, "examples": [{"ja": "お風呂の温度はいかがですか？", "vi": "Nhiệt độ bồn tắm thế nào?"},{"ja": "温度が高すぎます。", "vi": "Quá nóng."}], "care_example": "患者さんが安全に入浴できる温度を確認する"}, {"word": "湯", "reading": "ゆ", "kanji": "湯", "meaning": {"ja": "温かい水、お湯", "vi": "Nước nóng"}, "examples": [{"ja": "湯加減はいかがですか？", "vi": "Nhiệt độ nước thế nào?"},{"ja": "いい湯加減です。", "vi": "Nhiệt độ nước vừa phải."}], "care_example": "患者さんにお風呂のお湯の温度や具合を聞く"}, {"word": "滑りやすい", "reading": "すべりやすい", "kanji": "滑りやすい", "meaning": {"ja": "滑びりやすい状態、危ない", "vi": "Dễ trượt, nguy hiểm"}, "examples": [{"ja": "浴室は滑りやすいです。気をつけてください。", "vi": "Phòng tắm dễ trượt. Hãy cẩn thận."},{"ja": "滑り止めを使いましょう。", "vi": "Hãy sử dụng thảm chống trượt."}], "care_example": "患者さんが転倒しないよう注意を促す"}, {"word": "転倒", "reading": "てんとう", "kanji": "転倒", "meaning": {"ja": "倒れる、転ぶ", "vi": "Ngã,넘어지다"}, "examples": [{"ja": "浴室での転倒は危険です。", "vi": "Ngã trong phòng tắm là nguy hiểm."},{"ja": "転倒を防ぐために、手すりがあります。", "vi": "Có tay cầm để phòng chống ngã."}], "care_example": "患者さんに浴室の危険性を説明する"}, {"word": "洗う", "reading": "あらう", "kanji": "洗う", "meaning": {"ja": "汚れを落とす、清潔にする", "vi": "Rửa sạch, làm sạch"}, "examples": [{"ja": "背中を洗いましょう。", "vi": "Hãy để tôi rửa sạch lưng bạn."},{"ja": "丁寧に洗ってください。", "vi": "Vui lòng rửa sạch từng chỗ."}], "care_example": "患者さんの体を丁寧に洗う時の指導"}, {"word": "タオル", "reading": "たおる", "kanji": "タオル", "meaning": {"ja": "体を拭くための布", "vi": "Khăn lau"}, "examples": [{"ja": "タオルでふいてください。", "vi": "Vui lòng lau bằng khăn."},{"ja": "温かいタオルで拭きます。", "vi": "Tôi sẽ lau bằng khăn ấm."}], "care_example": "入浴後、患者さんの体をタオルで拭く時"}, {"word": "シャワー", "reading": "しゃわー", "kanji": "シャワー", "meaning": {"ja": "浴室の施設、水を流す装置", "vi": "Vòi sen"}, "examples": [{"ja": "シャワーで体を流します。", "vi": "Tôi sẽ rửa bằng vòi sen."},{"ja": "シャワーの温度に気をつけてください。", "vi": "Hãy cẩn thận với nhiệt độ vòi sen."}], "care_example": "患者さんがシャワーで体を洗う時の指導"}], "dialogue": ["介護職: 「お風呂の準備ができました。」", "患者さん: 「ありがとうございます。」", "介護職: 「温度はいかがですか？」", "患者さん: 「いい湯加減です。」", "介護職: 「浴室は滑りやすいです。気をつけてください。」", "患者さん: 「わかりました。手すりを持ちます。」", "介護職: 「はい。背中を丁寧に洗いますね。」"], "key_phrases": [{"ja": "お風呂の準備", "vi": "Chuẩn bị bồn tắm"},{"ja": "湯加減", "vi": "Nhiệt độ nước"},{"ja": "滑りやすい", "vi": "Dễ trượt"},{"ja": "転倒に気をつける", "vi": "Cẩn thận ngã"}], "cultural_note": {"ja": "入浴介助は、患者さんのプライバシーと尊厳を尊重しながら、安全と清潔を保つ重要なケアです。患者さんが快適に感じるような気配りと、転倒などの危険から守る配慮が必要です。", "vi": "Hỗ trợ tắm là chăm sóc quan trọng để duy trì an toàn và vệ sinh, đồng thời tôn trọng quyền riêng tư và nhân phẩm của bệnh nhân. Cần chăm sóc để bệnh nhân cảm thấy thoải mái và bảo vệ khỏi những nguy hiểm như ngã."}, "quiz": [{"question": {"ja": "浴室で最も危険な状況は？", "vi": "Tình huống nguy hiểm nhất ở phòng tắm là gì?"}, "options": [{"ja": "水が冷たい", "vi": "Nước lạnh"},{"ja": "滑って転倒する", "vi": "Trượt và ngã"},{"ja": "ผ้าขาดไป", "vi": "Khăn rách"},{"ja": "สบู่ทำให้ลื่น", "vi": "Xà phòng dễ trượt"}], "correct_answer": 1, "explanation": {"ja": "浴室での転倒は重大な事故につながるため、患者さんの安全が最優先です。", "vi": "Ngã ở phòng tắm có thể dẫn đến tai nạn nghiêm trọng, nên an toàn của bệnh nhân là ưu tiên hàng đầu."}, "difficulty": "medium"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = '介護の日本語（N5レベル）' LIMIT 1), 4, 1, 'vocabulary', '{"intro": {"ja": "排泄の時に使う言葉を学びます。「トイレに行きませんか」「お手伝いしましょう」など、患者さんのプライバシーを守りながら、丁寧な配慮が重要です。", "vi": "Học những từ sử dụng lúc vệ sinh. \"Bạn có muốn đi vệ sinh không?\" \"Để tôi giúp bạn\" v.v... Chăm sóc lịch sự để bảo vệ quyền riêng tư của bệnh nhân là quan trọng."}, "words": [{"word": "トイレ", "reading": "といれ", "kanji": "トイレ", "meaning": {"ja": "便所、化粧室", "vi": "Nhà vệ sinh, phòng vệ sinh"}, "examples": [{"ja": "トイレに行きませんか？", "vi": "Bạn có muốn đi vệ sinh không?"},{"ja": "トイレはこちらです。", "vi": "Nhà vệ sinh ở đây."}], "care_example": "患者さんをトイレに案内する時に使う"}, {"word": "便秘", "reading": "べんぴ", "kanji": "便秘", "meaning": {"ja": "便が出ない状態", "vi": "Táo bón"}, "examples": [{"ja": "便秘ですか？", "vi": "Bạn bị táo bón không?"},{"ja": "便秘の場合は、医者に相談してください。", "vi": "Nếu táo bón, hãy tham vấn bác sĩ."}], "care_example": "患者さんの排泄の問題について確認する"}, {"word": "排泄", "reading": "はいせつ", "kanji": "排泄", "meaning": {"ja": "体から不要な物質を出す", "vi": "T排泄, đi vệ sinh"}, "examples": [{"ja": "毎日、排泄があったかどうか確認します。", "vi": "Tôi kiểm tra xem mỗi ngày có đi vệ sinh không."},{"ja": "排泄の問題があります。", "vi": "Tôi có vấn đề vệ sinh."}], "care_example": "患者さんの排泄状況を記録する時の医療用語"}, {"word": "尿", "reading": "にょう", "kanji": "尿", "meaning": {"ja": "体から出る液体の廃棄物", "vi": "Nước tiểu"}, "examples": [{"ja": "尿に色がありますか？", "vi": "Nước tiểu có màu không?"},{"ja": "尿の回数を数えます。", "vi": "Tôi đếm số lần đi tiểu."}], "care_example": "医療記録で尿の状態や量を確認する"}, {"word": "便", "reading": "べん", "kanji": "便", "meaning": {"ja": "排泄物、固体の廃棄物", "vi": "Phân"}, "examples": [{"ja": "便の状態はいかがですか？", "vi": "Tình trạng phân của bạn thế nào?"},{"ja": "便が硬いですか？", "vi": "Phân cứng không?"}], "care_example": "患者さんの便の状態や量を観察する"}, {"word": "プライバシー", "reading": "ぷらいばしー", "kanji": "プライバシー", "meaning": {"ja": "個人の私生活、秘密", "vi": "Quyền riêng tư"}, "examples": [{"ja": "トイレはプライバシーが大事です。", "vi": "Quyền riêng tư ở nhà vệ sinh rất quan trọng."},{"ja": "プライバシーを守ります。", "vi": "Tôi sẽ bảo vệ quyền riêng tư của bạn."}], "care_example": "患者さんのプライバシー保護について説明する"}, {"word": "おむつ", "reading": "おむつ", "kanji": "おむつ", "meaning": {"ja": "排泄物を吸収する布製品", "vi": "Bỉm, tã"}, "examples": [{"ja": "おむつを変えましょう。", "vi": "Hãy để tôi thay tã cho bạn."},{"ja": "おむつが必要ですか？", "vi": "Bạn cần tã không?"}], "care_example": "患者さんの衛生管理のために使う医療用品"}, {"word": "手洗い", "reading": "てあらい", "kanji": "手洗い", "meaning": {"ja": "手を石鹸と水で洗う", "vi": "Rửa tay"}, "examples": [{"ja": "トイレの後、手洗いをしてください。", "vi": "Vui lòng rửa tay sau khi đi vệ sinh."},{"ja": "手洗いは大事です。", "vi": "Rửa tay là quan trọng."}], "care_example": "患者さんに感染症予防のために手洗いを促す"}], "dialogue": ["介護職: 「トイレに行きませんか？」", "患者さん: 「はい、お願いします。」", "介護職: 「こちらです。プライバシーは守ります。」", "患者さん: 「ありがとうございます。」", "介護職: 「（トイレ終了後）手洗いをしてください。」", "患者さん: 「わかりました。」", "介護職: 「排泄の問題がありましたら、いつでも言ってください。」"], "key_phrases": [{"ja": "トイレに行く", "vi": "Đi vệ sinh"},{"ja": "プライバシーを守る", "vi": "Bảo vệ quyền riêng tư"},{"ja": "手洗い", "vi": "Rửa tay"},{"ja": "排泄の状態", "vi": "Tình trạng vệ sinh"}], "cultural_note": {"ja": "排泄介助は最もプライバシーが必要なケアです。患者さんの尊厳を守りながら、衛生管理と感染予防を確実に行うことが、良いケア関係の基本です。", "vi": "Hỗ trợ vệ sinh là chăm sóc cần quyền riêng tư nhất. Bảo vệ nhân phẩm của bệnh nhân trong khi thực hiện quản lý vệ sinh và phòng chống lây nhiễm một cách chắc chắn là cơ sở của mối quan hệ chăm sóc tốt."}, "quiz": [{"question": {"ja": "排泄介助の際に最も重要なことは？", "vi": "Điều quan trọng nhất khi hỗ trợ vệ sinh là gì?"}, "options": [{"ja": "速度を優先すること", "vi": "Ưu tiên tốc độ"},{"ja": "患者さんのプライバシーと尊厳を守る", "vi": "Bảo vệ quyền riêng tư và nhân phẩm của bệnh nhân"},{"ja": "最小限の水を使う", "vi": "Sử dụng lượng nước tối thiểu"},{"ja": "患者さんを急かす", "vi": "Giục bệnh nhân"}], "correct_answer": 1, "explanation": {"ja": "排泄介助では、患者さんのプライバシーと尊厳の保護が最優先です。", "vi": "Khi hỗ trợ vệ sinh, bảo vệ quyền riêng tư và nhân phẩm của bệnh nhân là ưu tiên hàng đầu."}, "difficulty": "medium"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = '介護の日本語（N5レベル）' LIMIT 1), 5, 1, 'vocabulary', '{"intro": {"ja": "移動を手伝う時に使う言葉を学びます。「立ってください」「手を貸します」など、患者さんが安全に移動できるようにサポートするための言葉が重要です。", "vi": "Học những từ sử dụng khi giúp di chuyển. \"Đứng lên\" \"Để tôi giúp\" v.v... Những từ để hỗ trợ bệnh nhân di chuyển một cách an toàn là quan trọng."}, "words": [{"word": "立つ", "reading": "たつ", "kanji": "立つ", "meaning": {"ja": "足で立つ、起き上がる", "vi": "Đứng dậy, thẳng lên"}, "examples": [{"ja": "立ってください。", "vi": "Vui lòng đứng lên."},{"ja": "ゆっくり立ってください。", "vi": "Vui lòng đứng lên từ từ."}], "care_example": "患者さんを座った状態から立たせる時"}, {"word": "歩く", "reading": "あるく", "kanji": "歩く", "meaning": {"ja": "足で移動する、散歩する", "vi": "Đi bộ, bước đi"}, "examples": [{"ja": "一緒に歩きましょう。", "vi": "Chúng ta đi bộ cùng nhau."},{"ja": "ゆっくり歩いてください。", "vi": "Vui lòng đi bộ từ từ."}], "care_example": "患者さんと一緒に移動する時の提案"}, {"word": "手を貸す", "reading": "てをかす", "kanji": "手を貸す", "meaning": {"ja": "手を差し出して助ける", "vi": "Giúp đỡ, cho tay giúp"}, "examples": [{"ja": "手を貸します。", "vi": "Để tôi giúp bạn."},{"ja": "しっかり手を握ってください。", "vi": "Vui lòng nắm chặt tay tôi."}], "care_example": "患者さんが移動する際に身体的な支援を提供する"}, {"word": "バランス", "reading": "ばらんす", "kanji": "バランス", "meaning": {"ja": "均衡、安定性", "vi": "Cân bằng, sự ổn định"}, "examples": [{"ja": "バランスを保ってください。", "vi": "Vui lòng giữ thăng bằng."},{"ja": "バランスが悪いです。", "vi": "Cân bằng không tốt."}], "care_example": "患者さんが転倒しないようにバランスを維持するよう指導する"}, {"word": "車椅子", "reading": "くるまいす", "kanji": "車椅子", "meaning": {"ja": "車輪がついた椅子、移動を助けるツール", "vi": "Xe lăn"}, "examples": [{"ja": "車椅子に乗ってください。", "vi": "Vui lòng ngồi trên xe lăn."},{"ja": "車椅子で移動しましょう。", "vi": "Chúng ta di chuyển bằng xe lăn."}], "care_example": "移動能力の限定的な患者さんを支援する時"}, {"word": "ベッド", "reading": "べっど", "kanji": "ベッド", "meaning": {"ja": "寝るための家具", "vi": "Giường"}, "examples": [{"ja": "ベッドに横になってください。", "vi": "Vui lòng nằm xuống trên giường."},{"ja": "ベッドから起き上がるのを手伝います。", "vi": "Tôi sẽ giúp bạn dậy từ giường."}], "care_example": "患者さんがベッドとの間を移動する時の支援"}, {"word": "階段", "reading": "かいだん", "kanji": "階段", "meaning": {"ja": "高い場所へ上がるための道具", "vi": "Cầu thang"}, "examples": [{"ja": "階段は登れますか？", "vi": "Bạn có thể lên cầu thang không?"},{"ja": "階段での転倒に気をつけてください。", "vi": "Cẩn thận ngã trên cầu thang."}], "care_example": "患者さんの階段利用能力を確認する"}, {"word": "手すり", "reading": "てすり", "kanji": "手すり", "meaning": {"ja": "移動を支援するための棒、安全を確保するツール", "vi": "Tay cầm, thanh hỗ trợ"}, "examples": [{"ja": "手すりを持ってください。", "vi": "Vui lòng nắm tay cầm."},{"ja": "手すりがあるので、安全です。", "vi": "Có tay cầm nên an toàn."}], "care_example": "患者さんが手すりを使用して安全に移動するよう指導する"}], "dialogue": ["介護職: 「立ってください。ゆっくりです。」", "患者さん: 「はい。」", "介護職: 「手を貸します。しっかり握ってください。」", "患者さん: 「ありがとうございます。」", "介護職: 「バランスを保ってください。一緒に歩きましょう。」", "患者さん: 「わかりました。」", "介護職: 「階段は気をつけて。手すりを持ってください。」"], "key_phrases": [{"ja": "立ってください", "vi": "Đứng lên"},{"ja": "手を貸します", "vi": "Để tôi giúp"},{"ja": "ゆっくり歩く", "vi": "Đi bộ từ từ"},{"ja": "バランスを保つ", "vi": "Giữ thăng bằng"}], "cultural_note": {"ja": "移動介助は患者さんの独立性を尊重しながら、安全と転倒予防を確保するバランスの取れたケアです。患者さんの能力を評価し、必要な支援を提供することが、患者さんの自信と回復を促進します。", "vi": "Hỗ trợ di chuyển là chăm sóc cân bằng để tôn trọng tính độc lập của bệnh nhân, đồng thời đảm bảo an toàn và phòng chống ngã. Đánh giá khả năng của bệnh nhân và cung cấp hỗ trợ cần thiết thúc đẩy sự tự tin và phục hồi của bệnh nhân."}, "quiz": [{"question": {"ja": "患者さんの移動を支援する時、最も重要なことは？", "vi": "Điều quan trọng nhất khi hỗ trợ di chuyển cho bệnh nhân là gì?"}, "options": [{"ja": "速度を優先する", "vi": "Ưu tiên tốc độ"},{"ja": "患者さんの安全と転倒予防", "vi": "An toàn của bệnh nhân và phòng chống ngã"},{"ja": "患者さんを急かす", "vi": "Giục bệnh nhân"},{"ja": "できるだけ少なく支援する", "vi": "Hỗ trợ tối thiểu"}], "correct_answer": 1, "explanation": {"ja": "患者さんの安全と転倒予防が、移動介助の最優先事項です。", "vi": "An toàn của bệnh nhân và phòng chống ngã là ưu tiên hàng đầu của hỗ trợ di chuyển."}, "difficulty": "medium"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = '介護の日本語（N5レベル）' LIMIT 1), 6, 1, 'vocabulary', '{"intro": {"ja": "患者さんのバイタルサイン（生命徴候）を測定する時に使う言葉を学びます。「血圧を測ります」「体温を測ってください」など、医療的な確認が重要です。", "vi": "Học những từ sử dụng khi đo các dấu hiệu sống của bệnh nhân. \"Tôi sẽ đo huyết áp\" \"Vui lòng đo thân nhiệt\" v.v... Kiểm tra y tế quan trọng."}, "words": [{"word": "血圧", "reading": "けつあつ", "kanji": "血圧", "meaning": {"ja": "心臓が送る血液の圧力", "vi": "Huyết áp"}, "examples": [{"ja": "血圧を測ります。", "vi": "Tôi sẽ đo huyết áp."},{"ja": "血圧が高いです。", "vi": "Huyết áp cao."}], "care_example": "患者さんの健康管理のために毎日血圧を測定する"}, {"word": "体温", "reading": "たいおん", "kanji": "体温", "meaning": {"ja": "体の温度", "vi": "Thân nhiệt"}, "examples": [{"ja": "体温を測ってください。", "vi": "Vui lòng đo thân nhiệt."},{"ja": "体温が高いです。", "vi": "Thân nhiệt cao."}], "care_example": "患者さんが熱がないか、定期的に確認する"}, {"word": "脈拍", "reading": "みゃくはく", "kanji": "脈拍", "meaning": {"ja": "心臓の鼓動、心拍数", "vi": "Nhịp tim"}, "examples": [{"ja": "脈拍を測ります。", "vi": "Tôi sẽ đo nhịp tim."},{"ja": "脈拍が速いです。", "vi": "Nhịp tim nhanh."}], "care_example": "患者さんの心臓の健康状態を確認する"}, {"word": "呼吸", "reading": "こきゅう", "kanji": "呼吸", "meaning": {"ja": "空気を吸い、吐く、息をする", "vi": "Hô hấp, thở"}, "examples": [{"ja": "呼吸を数えます。", "vi": "Tôi sẽ đếm nhịp thở."},{"ja": "呼吸が浅いです。", "vi": "Thở nông."}], "care_example": "患者さんの呼吸の深さと規則性を観察する"}, {"word": "熱がある", "reading": "ねつがある", "kanji": "熱がある", "meaning": {"ja": "体温が高い、発熱している", "vi": "Có sốt, sốt cao"}, "examples": [{"ja": "患者さんは熱があります。", "vi": "Bệnh nhân có sốt."},{"ja": "熱があれば、医者に連絡します。", "vi": "Nếu có sốt, tôi sẽ liên hệ với bác sĩ."}], "care_example": "患者さんの体温が上昇している状態を報告する"}, {"word": "正常", "reading": "せいじょう", "kanji": "正常", "meaning": {"ja": "通常の状態、異常がない", "vi": "Bình thường, không bất thường"}, "examples": [{"ja": "血圧は正常です。", "vi": "Huyết áp bình thường."},{"ja": "体温は正常です。", "vi": "Thân nhiệt bình thường."}], "care_example": "患者さんのバイタルサインが良好であることを報告する"}, {"word": "異常", "reading": "いじょう", "kanji": "異常", "meaning": {"ja": "通常と違う状態、問題がある", "vi": "Bất thường, có vấn đề"}, "examples": [{"ja": "血圧に異常があります。", "vi": "Có bất thường về huyết áp."},{"ja": "異常があれば、報告します。", "vi": "Nếu có bất thường, tôi sẽ báo cáo."}], "care_example": "患者さんのバイタルサインに問題がある場合を報告する"}, {"word": "記録", "reading": "きろく", "kanji": "記録", "meaning": {"ja": "情報を書いて保存する", "vi": "Ghi chép, lưu trữ"}, "examples": [{"ja": "バイタルサインを記録します。", "vi": "Tôi sẽ ghi chép các dấu hiệu sống."},{"ja": "毎日の記録が大事です。", "vi": "Ghi chép hàng ngày rất quan trọng."}], "care_example": "患者さんのバイタルサインを毎日記録して管理する"}], "dialogue": ["介護職: 「血圧を測ります。楽にしてください。」", "患者さん: 「わかりました。」", "介護職: 「体温も測ります。」", "患者さん: 「はい。」", "介護職: 「脈拍と呼吸も確認します。」", "患者さん: 「大丈夫です。」", "介護職: 「すべて正常です。安心してください。」"], "key_phrases": [{"ja": "血圧を測る", "vi": "Đo huyết áp"},{"ja": "体温", "vi": "Thân nhiệt"},{"ja": "脈拍", "vi": "Nhịp tim"},{"ja": "正常/異常", "vi": "Bình thường/Bất thường"}], "cultural_note": {"ja": "バイタルサイン測定は、患者さんの健康状態を監視する基本的なケアです。正確な測定と記録は、医療チームが患者さんの状態変化を把握し、適切な対応を取るために不可欠です。", "vi": "Đo các dấu hiệu sống là chăm sóc cơ bản để theo dõi tình trạng sức khỏe của bệnh nhân. Đo lường và ghi chép chính xác là cần thiết để đội ngũ y tế nắm bắt những thay đổi trong tình trạng bệnh nhân và đưa ra phản ứng thích hợp."}, "quiz": [{"question": {"ja": "バイタルサイン測定の目的は？", "vi": "Mục đích của việc đo các dấu hiệu sống là gì?"}, "options": [{"ja": "時間を過ごす", "vi": "Để dành thời gian"},{"ja": "患者さんの健康状態を監視し、異常を早期に発見する", "vi": "Theo dõi sức khỏe bệnh nhân và phát hiện bất thường sớm"},{"ja": "患者さんを怖がらせる", "vi": "Để làm bệnh nhân sợ"},{"ja": "医者を忙しくさせる", "vi": "Để làm bác sĩ bận"}], "correct_answer": 1, "explanation": {"ja": "バイタルサイン測定は患者さんの健康管理と早期異常発見のための重要なケアです。", "vi": "Đo các dấu hiệu sống là chăm sóc quan trọng để quản lý sức khỏe bệnh nhân và phát hiện bất thường sớm."}, "difficulty": "medium"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = '介護の日本語（N5レベル）' LIMIT 1), 7, 1, 'vocabulary', '{"intro": {"ja": "シフト交代時に患者さんの状況を伝える時に使う言葉を学びます。「今日は・・・がありました」「明日は・・・に気をつけてください」など、正確で分かりやすい報告が重要です。", "vi": "Học những từ sử dụng khi chuyển giao tình trạng bệnh nhân giữa các ca làm việc. \"Hôm nay có~\" \"Ngày mai hãy chú ý~\" v.v... Báo cáo chính xác và dễ hiểu là quan trọng."}, "words": [{"word": "申し送り", "reading": "もうしおくり", "kanji": "申し送り", "meaning": {"ja": "シフト交代時に情報を引き継ぐ", "vi": "Chuyển giao thông tin giữa các ca làm việc"}, "examples": [{"ja": "申し送りがあります。", "vi": "Tôi có thông tin cần chuyển giao."},{"ja": "申し送りを聞いてください。", "vi": "Vui lòng nghe thông tin chuyển giao."}], "care_example": "朝の申し送りで前のシフトの情報を受け取る"}, {"word": "報告", "reading": "ほうこく", "kanji": "報告", "meaning": {"ja": "情報を上司やチームに伝える", "vi": "Báo cáo, thông báo"}, "examples": [{"ja": "患者さんのことを報告します。", "vi": "Tôi sẽ báo cáo tình trạng bệnh nhân."},{"ja": "重要な情報の報告が大事です。", "vi": "Báo cáo thông tin quan trọng rất cần thiết."}], "care_example": "患者さんの重要な変化を申し送りで報告する"}, {"word": "変化", "reading": "へんか", "kanji": "変化", "meaning": {"ja": "状態が変わることを意味する", "vi": "Thay đổi, sự thay đổi"}, "examples": [{"ja": "患者さんに変化がありました。", "vi": "Bệnh nhân có thay đổi."},{"ja": "良い変化です。", "vi": "Là một thay đổi tích cực."}], "care_example": "患者さんの症状や状態の改善や悪化を報告する"}, {"word": "注意", "reading": "ちゅうい", "kanji": "注意", "meaning": {"ja": "気をつけること、警告", "vi": "Chú ý, cảnh báo"}, "examples": [{"ja": "明日は転倒に注意してください。", "vi": "Ngày mai hãy chú ý để tránh ngã."},{"ja": "食事の時は注意が必要です。", "vi": "Cần chú ý lúc ăn cơm."}], "care_example": "次のシフトに患者さんで注意すべき点を伝える"}, {"word": "指示", "reading": "しじ", "kanji": "指示", "meaning": {"ja": "やるべきことを言う、命令する", "vi": "Chỉ dạn, hướng dẫn"}, "examples": [{"ja": "医者からの指示があります。", "vi": "Có chỉ dạn từ bác sĩ."},{"ja": "患者さんの食事制限の指示を守ってください。", "vi": "Vui lòng tuân theo chỉ dạn về chế độ ăn của bệnh nhân."}], "care_example": "医者からの特別な指示を申し送りで伝える"}, {"word": "薬", "reading": "くすり", "kanji": "薬", "meaning": {"ja": "病気や症状を治すために飲む物質", "vi": "Thuốc"}, "examples": [{"ja": "今日の薬は変わりました。", "vi": "Thuốc hôm nay đã thay đổi."},{"ja": "薬の種類と時間を確認してください。", "vi": "Vui lòng kiểm tra loại thuốc và thời gian."}], "care_example": "薬の変更や新しい処方を申し送りする"}, {"word": "食事制限", "reading": "しょくじせいげん", "kanji": "食事制限", "meaning": {"ja": "食べてはいけない食べ物がある状態", "vi": "Hạn chế chế độ ăn"}, "examples": [{"ja": "食事制限が新しくなりました。", "vi": "Hạn chế chế độ ăn đã thay đổi."},{"ja": "塩分の食事制限があります。", "vi": "Có hạn chế muối trong chế độ ăn."}], "care_example": "患者さんの食事制限の変更を次のシフトに伝える"}, {"word": "昨日の状態", "reading": "きのうのじょうたい", "kanji": "昨日の状態", "meaning": {"ja": "前の日の患者さんの状態", "vi": "Tình trạng hôm qua"}, "examples": [{"ja": "昨日の状態はどうでしたか？", "vi": "Hôm qua bệnh nhân thế nào?"},{"ja": "昨日の状態から改善しました。", "vi": "Đã cải thiện so với hôm qua."}], "care_example": "前のシフトから患者さんの状態を引き継ぐ"}], "dialogue": ["シフト交代：前のシフト: 「申し送りがあります。」", "新しいシフト: 「聞きます。」", "前のシフト: 「患者さんに変化がありました。昨日の血圧が高かったです。」", "新しいシフト: 「わかりました。注意します。」", "前のシフト: 「そして、医者からの新しい指示があります。食事制限が変わりました。」", "新しいシフト: 「どの食べ物が制限されていますか？」", "前のシフト: 「塩分が制限されています。確認してください。」"], "key_phrases": [{"ja": "申し送り", "vi": "Chuyển giao thông tin"},{"ja": "変化がありました", "vi": "Có thay đổi"},{"ja": "注意してください", "vi": "Hãy chú ý"},{"ja": "医者からの指示", "vi": "Chỉ dạn từ bác sĩ"}], "cultural_note": {"ja": "申し送りは、患者さんの安全と継続的なケアの質を確保するために最も重要なコミュニケーションです。正確で漏れない情報の伝達が、医療ミスを防ぎ、患者さんの信頼を守ります。", "vi": "Chuyển giao thông tin là giao tiếp quan trọng nhất để đảm bảo an toàn bệnh nhân và chất lượng chăm sóc liên tục. Truyền đạt thông tin chính xác và không bỏ sót ngăn chặn sai sót y tế và bảo vệ sự tin tưởng của bệnh nhân."}, "quiz": [{"question": {"ja": "申し送りの目的は？", "vi": "Mục đích của chuyển giao thông tin là gì?"}, "options": [{"ja": "時間を過ごす", "vi": "Để dành thời gian"},{"ja": "患者さんの情報を次のシフトに伝え、継続的なケアの質を確保する", "vi": "Chuyển giao thông tin bệnh nhân để đảm bảo chất lượng chăm sóc liên tục"},{"ja": "おしゃべりする", "vi": "Để nói chuyện"},{"ja": "前のシフトをうらむ", "vi": "Để than phiền ca làm việc trước"}], "correct_answer": 1, "explanation": {"ja": "申し送りは患者さんの安全と継続的なケアを確保するための重要なコミュニケーションです。", "vi": "Chuyển giao thông tin là giao tiếp quan trọng để đảm bảo an toàn bệnh nhân và chăm sóc liên tục."}, "difficulty": "medium"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = '介護の日本語（N5レベル）' LIMIT 1), 8, 1, 'vocabulary', '{"intro": {"ja": "患者さんの家族と関わる時に使う言葉を学びます。「お疲れ様です」「患者さんの状況をお伝えします」など、家族への配慮と正確な情報提供が重要です。", "vi": "Học những từ sử dụng khi liên lạc với gia đình bệnh nhân. \"Cảm ơn quý vị\" \"Tôi sẽ thông báo tình trạng bệnh nhân\" v.v... Chăm sóc gia đình và cung cấp thông tin chính xác là quan trọng."}, "words": [{"word": "いつもお世話になっています", "reading": "いつもおせわになっています", "kanji": "いつもお世話になっています", "meaning": {"ja": "家族にケアのお礼を言う敬語の挨拶", "vi": "Lời chào lịch sự cảm ơn gia đình về sự chăm sóc"}, "examples": [{"ja": "いつもお世話になっています。ありがとうございます。", "vi": "Cảm ơn quý vị luôn luôn chăm sóc. Xin cảm ơn."},{"ja": "お母さん、いつもお世話になっています。", "vi": "Bà, cảm ơn quý vị luôn luôn chăm sóc."}], "care_example": "患者さんの家族に来院時に挨拶する時"}, {"word": "ご様子", "reading": "ごようす", "kanji": "ご様子", "meaning": {"ja": "患者さんの状態を敬語で言う", "vi": "Tình trạng của bệnh nhân (từ lịch sự)"}, "examples": [{"ja": "お母さんのご様子はどうですか？", "vi": "Bà của bạn thế nào?"},{"ja": "ご様子をお伝えします。", "vi": "Tôi sẽ thông báo tình trạng."}], "care_example": "患者さんの状態について家族に情報を提供する"}, {"word": "回復", "reading": "かいふく", "kanji": "回復", "meaning": {"ja": "良くなる、元気を取り戻す", "vi": "Phục hồi, lấy lại sức khỏe"}, "examples": [{"ja": "患者さんの回復が順調です。", "vi": "Bệnh nhân phục hồi tốt."},{"ja": "回復を祈ります。", "vi": "Tôi mong bạn sẽ phục hồi."}], "care_example": "患者さんの改善状況を家族に報告する"}, {"word": "悪化", "reading": "あっか", "kanji": "悪化", "meaning": {"ja": "悪くなる、症状が増す", "vi": "Xấu đi, tình trạng trở nên tồi tệ hơn"}, "examples": [{"ja": "患者さんの状態に悪化がありました。", "vi": "Tình trạng bệnh nhân xấu đi."},{"ja": "悪化を防ぐことが大事です。", "vi": "Ngăn chặn tình trạng xấu đi là quan trọng."}], "care_example": "患者さんの悪い変化を家族に知らせる"}, {"word": "面会", "reading": "めんかい", "kanji": "面会", "meaning": {"ja": "患者さんに会いに来ることを意味する", "vi": "Thăm viếng, gặp gỡ"}, "examples": [{"ja": "いつでも面会に来てください。", "vi": "Vui lòng thoải mái đến thăm viếng."},{"ja": "面会の時間は10時から18時までです。", "vi": "Thời gian thăm viếng là từ 10 giờ đến 18 giờ."}], "care_example": "患者さんの家族に面会について知らせる"}, {"word": "健康", "reading": "けんこう", "kanji": "健康", "meaning": {"ja": "病気がない、元気な状態", "vi": "Sức khỏe, khỏe mạnh"}, "examples": [{"ja": "患者さんの健康が大事です。", "vi": "Sức khỏe của bệnh nhân rất quan trọng."},{"ja": "健康を保つために、毎日運動します。", "vi": "Để duy trì sức khỏe, tôi tập thể dục hàng ngày."}], "care_example": "患者さんの長期的な健康維持について家族と話し合う"}, {"word": "相談", "reading": "そうだん", "kanji": "相談", "meaning": {"ja": "問題について意見を交わす、助言を求める", "vi": "Tham vấn, bàn bạc"}, "examples": [{"ja": "何か心配なことがあれば、いつでも相談してください。", "vi": "Nếu có lo lắng, vui lòng tham vấn với tôi bất cứ lúc nào."},{"ja": "医者と相談しましょう。", "vi": "Hãy tham vấn với bác sĩ."}], "care_example": "患者さんの長期的なケアについて家族と相談する"}, {"word": "感謝", "reading": "かんしゃ", "kanji": "感謝", "meaning": {"ja": "ありがたいと感じることを言葉で表す", "vi": "Cảm ơn, sự biết ơn"}, "examples": [{"ja": "いつもの協力に感謝します。", "vi": "Cảm ơn sự hợp tác của quý vị."},{"ja": "家族のサポートに感謝です。", "vi": "Cảm ơn sự hỗ trợ của gia đình."}], "care_example": "患者さんの家族に感謝の気持ちを伝える"}], "dialogue": ["介護職: 「いつもお世話になっています。」", "ご家族: 「こちらこそ。母の様子はどうですか？」", "介護職: 「ご様子をお伝えします。回復が順調です。」", "ご家族: 「そうですか。よかった。」", "介護職: 「はい。毎日、運動をして、健康を保っています。」", "ご家族: 「何か心配なことはありますか？」", "介護職: 「いいえ。何かあれば、いつでも相談します。ご家族のサポートに感謝です。」"], "key_phrases": [{"ja": "いつもお世話になっています", "vi": "Cảm ơn quý vị luôn luôn chăm sóc"},{"ja": "ご様子をお伝えします", "vi": "Tôi sẽ thông báo tình trạng"},{"ja": "回復が順調です", "vi": "Phục hồi tốt"},{"ja": "いつでも相談してください", "vi": "Vui lòng tham vấn với tôi bất cứ lúc nào"}], "cultural_note": {"ja": "家族との関わりは、患者さんのケアの成功を左右する重要な要素です。家族との信頼関係を築き、正確で温かい情報提供をすることで、患者さんと家族両方の安心と満足度を高めることができます。", "vi": "Mối quan hệ với gia đình là yếu tố quan trọng quyết định sự thành công của chăm sóc bệnh nhân. Bằng cách xây dựng mối quan hệ tin tưởng với gia đình và cung cấp thông tin chính xác và ấm áp, bạn có thể nâng cao sự yên tâm và sự hài lòng của cả bệnh nhân và gia đình."}, "quiz": [{"question": {"ja": "家族との関わりで最も重要なことは？", "vi": "Điều quan trọng nhất khi liên lạc với gia đình là gì?"}, "options": [{"ja": "家族を邪魔と見なす", "vi": "Coi gia đình là trở ngại"},{"ja": "信頼関係を築き、正確で温かい情報提供をする", "vi": "Xây dựng mối quan hệ tin tưởng và cung cấp thông tin chính xác"},{"ja": "家族に嘘をつく", "vi": "Nói dối gia đình"},{"ja": "患者さんについて話さない", "vi": "Không nói về bệnh nhân"}], "correct_answer": 1, "explanation": {"ja": "家族との信頼関係と正確な情報提供が、患者さんのケアの成功に不可欠です。", "vi": "Mối quan hệ tin tưởng với gia đình và cung cấp thông tin chính xác là cần thiết cho sự thành công của chăm sóc bệnh nhân."}, "difficulty": "medium"}]}' );
